import { DEFAULT_SITE_TENANT_CURRENCY_SYMBOL, EMPTY_SET, USD } from '../../const';
import { CurrencyFormatter } from '../formatter';

/**
 * DC格式化模式，针对美元格式化金额
 */
const cf = new CurrencyFormatter({
    pattern: 'D C',
    code: USD,
    decimal: 2,
    emptySet: EMPTY_SET,
    symbol: DEFAULT_SITE_TENANT_CURRENCY_SYMBOL,
});

export const formatUsCurrency = cf.format;

export const formatUsAmount = cf.amount;

export const getUsCurrencySymbol = cf.getSymbol;
